import "./App.css";

import LoginButton from "./Components/Login/LoginButton";
import LogoutButton from "./Components/Login/LogoutButton";
const { isAuthenticated } = useAuth0();

function App() {
  return (
    <div className="App">
      <LoginButton />
      <LogoutButton />
      {isAuthenticated ? <Home /> : <Login />}
    </div>
  );
}

export default App;
